'use server'

import { updateTag } from 'next/cache'
import { redirect } from 'next/navigation'
import { addPost } from './posts'

export async function createPost(formData: FormData) {
  const title = String(formData.get('title') ?? '').trim()

  if (!title) {
    throw new Error('Title is required')
  }

  const post = await addPost({ title })

  // Use updateTag, not revalidateTag, so the next request blocks for fresh data
  // instead of serving stale cached content.
  updateTag('posts')

  redirect(`/?created=${post.id}`)
}

import { cacheTag } from 'next/cache'

type Post = {
  id: number
  title: string
}

const globalForPosts = globalThis as typeof globalThis & {
  __postsStore?: Post[]
}

function getPostsStore() {
  if (!globalForPosts.__postsStore) {
    globalForPosts.__postsStore = [
      { id: 1, title: 'First post' },
      { id: 2, title: 'Second post' }
    ]
  }

  return globalForPosts.__postsStore
}

export async function getPosts() {
  'use cache'

  cacheTag('posts')

  return getPostsStore()
}

export async function addPost({ title }: { title: string }) {
  const posts = getPostsStore()
  const post = {
    id: posts.length ? Math.max(...posts.map((item) => item.id)) + 1 : 1,
    title
  }

  posts.unshift(post)

  return post
}

import { createPost } from './actions'
import { getPosts } from './posts'

export default async function Home() {
  const posts = await getPosts()

  return (
    <main style={{ fontFamily: 'sans-serif', margin: '40px auto', maxWidth: 640 }}>
      <h1>Posts</h1>

      <form action={createPost} style={{ display: 'grid', gap: 12, marginBottom: 24 }}>
        <input name="title" placeholder="Post title" required />
        <button type="submit">Create post</button>
      </form>

      <ul>
        {posts.map((post) => (
          <li key={post.id}>{post.title}</li>
        ))}
      </ul>
    </main>
  )
}

